// monster-resident — a resident MCP server exposing UCAN-verified orchestration
// to local fat-client stations. Part of the monster family; built on the Rust
// `a0n-auth` UCAN crate and the monster-guard enforcement path.
//
// Usage:
//   monster-resident                 # serve MCP over stdio (JSON-RPC 2.0)
//   monster-resident serve           # same
//   monster-resident whoami          # print the resident root DID
//   monster-resident grant --audience <did> --with <resource>
//                          [--can <action>] [--caps fs,net] [--ttl <secs>]
//                                    # mint a root-signed station capability (token to stdout)
//
// MCP tools:
//   whoami       -> the resident root DID
//   orchestrate  -> { ucan, name, args? }: verify the caller's UCAN (delegation
//                   chain + revocation, rooted at this resident's root, granting
//                   orchestrate/run on plugin:<name>), then run the delegated
//                   command via .bin/<name> (monster-guard sandbox + lease).

use std::io::{self, BufRead, Write};

mod store;

use a0n_auth::ucan::issue;
use a0n_auth::{check_capability, delegate, verify_chain, Capability, IssueOptions, Keypair};
use monster_swarm::auto::{self, AutoPolicy};
use monster_swarm::budget::Caste;
use monster_swarm::ops::{self as swarm_ops, BreachRequest, SpawnRequest, UpdateRequest};
use serde_json::{json, Value};

const PROTOCOL_VERSION: &str = "2024-11-05";
const SERVER_NAME: &str = "monster-resident";
const SERVER_VERSION: &str = "0.1.0";

fn main() {
    let args: Vec<String> = std::env::args().collect();
    match args.get(1).map(String::as_str) {
        None | Some("serve") => serve(),
        Some("whoami") => cmd_whoami(),
        Some("grant") => cmd_grant(&args[2..]),
        Some("verify") => cmd_verify(&args[2..]),
        Some("keygen") => cmd_keygen(),
        Some("delegate-token") => cmd_delegate_token(&args[2..]),
        Some("-h") | Some("--help") => usage(),
        Some(other) => {
            eprintln!("monster-resident: unknown subcommand '{other}'");
            usage();
            std::process::exit(2);
        }
    }
}

fn usage() {
    println!("monster-resident — UCAN-verified orchestration MCP server");
    println!();
    println!("  monster-resident [serve]   serve MCP over stdio");
    println!("  monster-resident whoami    print the resident root DID");
    println!("  monster-resident grant --audience <did> --with <resource> [--can <action>] [--caps fs,net] [--ttl <secs>]");
    println!("  monster-resident verify <token> [--cap <action>] [--with <resource>] [--require-rooted]   # JSON out; exit 0 valid / 2 invalid");
}

fn cmd_whoami() {
    match store::ensure_root() {
        Ok(root) => println!("{}", root.did()),
        Err(e) => {
            eprintln!("monster-resident: {e}");
            std::process::exit(1);
        }
    }
}

fn cmd_grant(args: &[String]) {
    let mut audience: Option<String> = None;
    let mut resource: Option<String> = None;
    let mut can = "orchestrate/run".to_string();
    let mut caps: Option<String> = None;
    let mut ttl: i64 = 24 * 60 * 60;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--audience" => { i += 1; audience = args.get(i).cloned(); }
            "--with" => { i += 1; resource = args.get(i).cloned(); }
            "--can" => { i += 1; if let Some(v) = args.get(i) { can = v.clone(); } }
            "--caps" => { i += 1; caps = args.get(i).cloned(); }
            "--ttl" => { i += 1; ttl = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(ttl); }
            other => { eprintln!("monster-resident grant: unexpected arg '{other}'"); std::process::exit(2); }
        }
        i += 1;
    }
    let audience = audience.unwrap_or_else(|| die("grant: --audience <did> required"));
    let resource = resource.unwrap_or_else(|| die("grant: --with <resource> required"));
    let root = store::ensure_root().unwrap_or_else(|e| die(&e));

    let constraints = caps.map(|c| {
        let list: Vec<String> = c
            .split(',')
            .map(str::trim)
            .filter(|s| !s.is_empty() && *s != "-")
            .map(String::from)
            .collect();
        json!({ "caps": list })
    });
    let cap = Capability {
        can,
        with: resource,
        constraints,
    };
    let token = issue(&root, &audience, &[cap], ttl, &IssueOptions::default())
        .unwrap_or_else(|e| die(&e.to_string()));
    println!("{token}");
}

fn die(msg: &str) -> ! {
    eprintln!("monster-resident: {msg}");
    std::process::exit(2);
}

// Generate a fresh identity (the holder of a delegation hop: a user, thoth, or
// a subagent). Prints {did, secret}; keep the secret to delegate onward.
fn cmd_keygen() {
    let kp = Keypair::generate();
    println!(
        "{}",
        serde_json::to_string(&json!({ "did": kp.did(), "secret": kp.secret_hex() }))
            .unwrap_or_default()
    );
}

// Holder-side attenuated delegation: a party (user/thoth) whose DID is the
// parent token's audience re-delegates a subset of capabilities onward. This is
// how users delegate to thoth, and thoth delegates to subagents.
fn cmd_delegate_token(args: &[String]) {
    let mut parent: Option<String> = None;
    let mut issuer_secret: Option<String> = None;
    let mut audience: Option<String> = None;
    let mut can = "orchestrate/run".to_string();
    let mut resource: Option<String> = None;
    let mut caps: Option<String> = None;
    let mut ttl: i64 = 60 * 60;
    let mut i = 0;
    while i < args.len() {
        match args[i].as_str() {
            "--parent" => { i += 1; parent = args.get(i).cloned(); }
            "--issuer-secret" => { i += 1; issuer_secret = args.get(i).cloned(); }
            "--audience" => { i += 1; audience = args.get(i).cloned(); }
            "--can" => { i += 1; if let Some(v) = args.get(i) { can = v.clone(); } }
            "--with" => { i += 1; resource = args.get(i).cloned(); }
            "--caps" => { i += 1; caps = args.get(i).cloned(); }
            "--ttl" => { i += 1; ttl = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(ttl); }
            other => die(&format!("delegate-token: unexpected arg '{other}'")),
        }
        i += 1;
    }
    let parent = parent.unwrap_or_else(|| die("delegate-token: --parent <token> required"));
    let secret = issuer_secret.unwrap_or_else(|| die("delegate-token: --issuer-secret <hex> required"));
    let audience = audience.unwrap_or_else(|| die("delegate-token: --audience <did> required"));
    let resource = resource.unwrap_or_else(|| die("delegate-token: --with <resource> required"));
    let issuer = Keypair::from_secret_hex(&secret).unwrap_or_else(|e| die(&e.to_string()));

    let constraints = caps.map(|c| {
        let list: Vec<String> = c
            .split(',')
            .map(str::trim)
            .filter(|s| !s.is_empty() && *s != "-")
            .map(String::from)
            .collect();
        json!({ "caps": list })
    });
    let cap = Capability { can, with: resource, constraints };
    let token = delegate(&parent, &issuer, &audience, &[cap], ttl)
        .unwrap_or_else(|e| die(&format!("delegation rejected: {e}")));
    println!("{token}");
}

// Canonical verifier other languages (e.g. the TS thoth gate) can shell out to.
// Verifies the delegation chain (user -> thoth -> subagent), revocation, and an
// optional required capability; emits JSON and exits 0 (valid) / 2 (invalid).
fn cmd_verify(args: &[String]) {
    if args.is_empty() {
        die("verify: <token> required (optionally --cap <can> --with <resource> --require-rooted)");
    }
    let token = &args[0];
    let mut cap_can: Option<String> = None;
    let mut cap_with: Option<String> = None;
    let mut require_rooted = false;
    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--cap" => { i += 1; cap_can = args.get(i).cloned(); }
            "--with" => { i += 1; cap_with = args.get(i).cloned(); }
            "--require-rooted" => { require_rooted = true; }
            other => die(&format!("verify: unexpected arg '{other}'")),
        }
        i += 1;
    }

    let root = store::ensure_root().unwrap_or_else(|e| die(&e));
    let rev = store::load_revocations();
    let result = verify_chain(token, Some(&rev), None);

    let mut valid = result.valid;
    let mut error = result.error.clone();
    let leaf = result.chain.first();
    let rooted_here = result.root_issuer.as_deref() == Some(root.did());

    if valid && require_rooted && !rooted_here {
        valid = false;
        error = Some("capability is not rooted at this resident".to_string());
    }
    if valid {
        if let (Some(can), Some(with)) = (&cap_can, &cap_with) {
            let required = Capability { can: can.clone(), with: with.clone(), constraints: None };
            match leaf {
                Some(l) if check_capability(&l.att, &required) => {}
                _ => {
                    valid = false;
                    error = Some(format!("capability not granted: {can} on {with}"));
                }
            }
        }
    }

    let caps: Vec<Value> = leaf
        .map(|l| {
            l.att
                .iter()
                .map(|c| json!({ "can": c.can, "with": c.with, "constraints": c.constraints }))
                .collect()
        })
        .unwrap_or_default();
    let out = json!({
        "valid": valid,
        "rootIssuer": result.root_issuer,
        "rootedHere": rooted_here,
        "issuer": leaf.map(|l| l.iss.clone()),
        "audience": leaf.map(|l| l.aud.clone()),
        "depth": result.chain.len(),
        "capabilities": caps,
        "error": error,
    });
    println!("{}", serde_json::to_string(&out).unwrap_or_default());
    std::process::exit(if valid { 0 } else { 2 });
}

// ----------------------------------------------------------------------------
// MCP server (stdio, newline-delimited JSON-RPC 2.0)
// ----------------------------------------------------------------------------

fn serve() {
    let root = match store::ensure_root() {
        Ok(r) => r,
        Err(e) => {
            eprintln!("monster-resident: cannot load root identity: {e}");
            std::process::exit(1);
        }
    };
    eprintln!("monster-resident: serving MCP over stdio (root {})", root.did());

    let stdin = io::stdin();
    let mut stdout = io::stdout();
    for line in stdin.lock().lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => break,
        };
        if line.trim().is_empty() {
            continue;
        }
        let req: Value = match serde_json::from_str(&line) {
            Ok(v) => v,
            Err(e) => {
                let resp = error_resp(&Value::Null, -32700, &format!("parse error: {e}"));
                write_msg(&mut stdout, &resp);
                continue;
            }
        };
        if let Some(resp) = handle(&req, &root.did().to_string()) {
            write_msg(&mut stdout, &resp);
        }
    }
}

fn write_msg(out: &mut impl Write, msg: &Value) {
    let _ = writeln!(out, "{}", serde_json::to_string(msg).unwrap_or_default());
    let _ = out.flush();
}

fn success_resp(id: &Value, result: Value) -> Value {
    json!({ "jsonrpc": "2.0", "id": id, "result": result })
}

fn error_resp(id: &Value, code: i64, message: &str) -> Value {
    json!({ "jsonrpc": "2.0", "id": id, "error": { "code": code, "message": message } })
}

/// Returns Some(response) for requests, None for notifications.
fn handle(req: &Value, root_did: &str) -> Option<Value> {
    let method = req.get("method").and_then(Value::as_str).unwrap_or("");
    let id = req.get("id").cloned();

    // Notifications have no id and get no response.
    if id.is_none() {
        return None;
    }
    let id = id.unwrap();

    match method {
        "initialize" => {
            let client_proto = req
                .get("params")
                .and_then(|p| p.get("protocolVersion"))
                .and_then(Value::as_str)
                .unwrap_or(PROTOCOL_VERSION)
                .to_string();
            Some(success_resp(
                &id,
                json!({
                    "protocolVersion": client_proto,
                    "capabilities": { "tools": {} },
                    "serverInfo": { "name": SERVER_NAME, "version": SERVER_VERSION }
                }),
            ))
        }
        "ping" => Some(success_resp(&id, json!({}))),
        "tools/list" => Some(success_resp(&id, tools_list())),
        "tools/call" => Some(handle_tool_call(&id, req, root_did)),
        other => Some(error_resp(&id, -32601, &format!("method not found: {other}"))),
    }
}

